ALTER TABLE public.forms ADD COLUMN IF NOT EXISTS show_in_open_data boolean NOT NULL DEFAULT false;
ALTER TABLE public.laporan_masyarakat ADD COLUMN IF NOT EXISTS ticket_code text, ADD COLUMN IF NOT EXISTS pelapor_id uuid;

DO $$ BEGIN ALTER TABLE public.forms ADD CONSTRAINT forms_pkey PRIMARY KEY (id); EXCEPTION WHEN duplicate_object THEN NULL; WHEN invalid_table_definition THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE public.form_submissions ADD CONSTRAINT form_submissions_pkey PRIMARY KEY (id); EXCEPTION WHEN duplicate_object THEN NULL; WHEN invalid_table_definition THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE public.generated_documents ADD CONSTRAINT generated_documents_pkey PRIMARY KEY (id); EXCEPTION WHEN duplicate_object THEN NULL; WHEN invalid_table_definition THEN NULL; END $$;
